const client = $('Webhook').first().json.query?.client || '';
const csvText = $json.data || '';

function splitLine(line) {
  const res = []; let cur = '', inQ = false;
  for (let i = 0; i < line.length; i++) {
    const c = line[i];
    if (c === '"') { if (inQ && line[i+1]==='"') { cur+='"'; i++; } else inQ=!inQ; }
    else if (c === ',' && !inQ) { res.push(cur); cur=''; }
    else cur += c;
  }
  res.push(cur);
  return res;
}

const lines = csvText.trim().split(/\r?\n/);
if (lines.length < 2) return [{ json: { items: [] } }];

const hdr = splitLine(lines[0]).map(h => h.trim());
const rows = lines.slice(1).map(line => {
  const cells = splitLine(line);
  const obj = {};
  hdr.forEach((h, i) => { obj[h] = (cells[i] || '').trim(); });
  // Если в таблице дублирующиеся client_name (client_name.1 и т.п.) — берём первое непустое
  if (!obj.client_name) {
    const fallback = Object.keys(obj).find(k => k.startsWith('client_name') && obj[k]);
    if (fallback) obj.client_name = obj[fallback];
  }
  return obj;
}).filter(r => Object.values(r).some(v => v));

const filtered = client ? rows.filter(r => r.client_name === client) : rows;

return [{ json: { items: filtered } }];
